(function(w){"use strict";const ID="frequency-period";function compute(x){const mode=x.mode||'frequency',v=Number(x.value);if(!Number.isFinite(v)||v<=0)return{error:"0보다 큰 값을 입력해 주세요."};return mode==='frequency'?{kind:'period',value:1/v}:{kind:'frequency',value:1/v}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>입력 종류</label><select class="hm-calc-select"><option value="frequency">주파수 (Hz) → 주기</option><option value="period">주기 (s) → 주파수</option></select></div><div class="hm-calc-field"><label>값</label><input class="hm-calc-input" inputmode="decimal"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const mode=root.querySelector("select"),input=root.querySelector("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({mode:mode.value,value:api.parseNumber(input.value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}const isP=r.kind==='period';api.setMessage(msg,"");api.setResult(res,api.resultCard(isP?'주기':'주파수',`${api.formatNumber(r.value,10)} ${isP?'s':'Hz'}`,'f = 1 ÷ T'));});}
w.HM_CALC.register(ID,{compute,render});})(window);
